document.addEventListener('DOMContentLoaded', () => {
    const app = document.getElementById('app');
    if (!app) {
        console.error('Root element #app not found!');
        return;
    }

    // --- Real-time Metrics Data ---
    const totalSalesElem = document.getElementById('totalSales');
    const newOrdersElem = document.getElementById('newOrders');
    const avgRevenueElem = document.getElementById('avgRevenue');
    const profitMarginElem = document.getElementById('profitMargin');

    let currentSales = 12345678;
    let currentOrders = 1234;
    let currentRevenue = 567.89;
    let currentProfit = 34.5;

    function updateMetrics() {
        // Simulate changes
        const salesChange = Math.random() * 1000 - 500; // -500 to 500
        const ordersChange = Math.floor(Math.random() * 20) - 10;
        const revenueChange = Math.random() * 5 - 2.5;
        const profitChange = Math.random() * 0.5 - 0.25;

        currentSales += salesChange;
        currentOrders += ordersChange;
        currentRevenue += revenueChange;
        currentProfit += profitChange;

        // Ensure values don't go too low for demo purposes
        currentSales = Math.max(10000000, currentSales);
        currentOrders = Math.max(1000, currentOrders);
        currentRevenue = Math.max(500, currentRevenue);
        currentProfit = Math.max(30, currentProfit);

        // Update UI
        totalSalesElem.textContent = `$${Math.round(currentSales).toLocaleString()}`;
        newOrdersElem.textContent = Math.round(currentOrders).toLocaleString();
        avgRevenueElem.textContent = `$${currentRevenue.toFixed(2)}`;
        profitMarginElem.textContent = `${currentProfit.toFixed(1)}%`;

        // Apply dynamic change indicator
        updateChangeIndicator(totalSalesElem.nextElementSibling, salesChange);
        updateChangeIndicator(newOrdersElem.nextElementSibling, ordersChange);
        updateChangeIndicator(avgRevenueElem.nextElementSibling, revenueChange);
        updateChangeIndicator(profitMarginElem.nextElementSibling, profitChange);
    }

    function updateChangeIndicator(element, change) {
        element.textContent = `${change > 0 ? '+' : ''}${change.toFixed(1)}%`;
        element.classList.remove('positive', 'negative');
        if (change > 0) {
            element.classList.add('positive');
        } else if (change < 0) {
            element.classList.add('negative');
        }
    }

    // Initial update and then every 3 seconds
    updateMetrics();
    setInterval(updateMetrics, 3000);

    // --- Live Product Feed Data ---
    const productGrid = document.getElementById('productGrid');
    const productData = [
        { id: 1, name: "Quantum Processor X", price: 1299.99, image: "https://images.unsplash.com/photo-1617042301193-d2507851d7c3?q=80&w=2942&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
        { id: 2, name: "Neural Interface Headset", price: 799.50, image: "https://images.unsplash.com/photo-1593570530725-7289d023190b?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
        { id: 3, name: "Fusion Power Core", price: 2499.00, image: "https://images.unsplash.com/photo-1627843075276-857e49195d9a?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
        { id: 4, name: "Holographic Display Unit", price: 1499.99, image: "https://images.unsplash.com/photo-1618305011681-42353360b0af?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
        { id: 5, name: "Bio-Enhancement Serum", price: 399.00, image: "https://images.unsplash.com/photo-1606820872659-1e3bbbfd9860?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
        { id: 6, name: "Automated Drone System", price: 899.00, image: "https://images.unsplash.com/photo-1601618357871-2b0e40882e75?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D" },
    ];

    function renderProducts() {
        productGrid.innerHTML = ''; // Clear existing products
        productData.forEach((product, index) => {
            const productCard = document.createElement('div');
            productCard.className = 'product-card';
            productCard.style.animationDelay = `${index * 0.1}s`; // Staggered animation

            productCard.innerHTML = `
                <img src="${product.image}" alt="${product.name}">
                <div class="product-info">
                    <h3 class="product-name">${product.name}</h3>
                    <p class="product-price">$${product.price.toFixed(2)}</p>
                    <button class="add-to-cart-btn">Add to Cart</button>
                </div>
            `;
            productGrid.appendChild(productCard);
        });
    }

    renderProducts();

    // Simulate product price changes
    setInterval(() => {
        const randomIndex = Math.floor(Math.random() * productData.length);
        const product = productData[randomIndex];
        const priceChange = (Math.random() * 50 - 25); // +/- $25
        product.price = Math.max(100, product.price + priceChange); // Ensure price doesn't go below $100
        renderProducts(); // Re-render to show updated price
    }, 5000);

    // --- Chart.js Configuration ---

